+                            width: 32,
+                            height: 32,
+                            errorBuilder: (c, e, s) => const SizedBox(),
+                          ),
+                        ),
+                      Expanded(
+                        child: Text(
+                          widget.channelName,
+                          style: const TextStyle(
+                            color: Colors.white,
+                            fontSize: 18,
+                            fontWeight: FontWeight.w600,
